 94	function renderHighlightedSource(markdown: string) {
 95	  if (!markdown) {
 96	    return `<span class="md-line md-line-placeholder"><span class="md-token md-token-placeholder"># Start writing
 97	
 98	Use headings, lists, quotes, links, and code without leaving markdown source.</span></span>`;
 99	  }
100	
101	  const lines = markdown.replace(/\r\n?/g, "\n").split("\n");
102	  const highlightedLines: string[] = [];
103	  let insideFence = false;
104	
105	  for (const line of lines) {
106	    const trimmedLine = line.trim();
107	
108	    if (!insideFence && /^(\s*)(#{1,6})(\s+)(.*)$/.test(line)) {
109	      const [, indent = "", hashes = "", gap = "", content = ""] = line.match(/^(\s*)(#{1,6})(\s+)(.*)$/) ?? [];
110	      highlightedLines.push(
111	        `<span class="md-line md-line-heading">${escapeSourceHtml(indent)}<span class="md-token md-token-heading-marker">${escapeSourceHtml(hashes)}</span>${escapeSourceHtml(gap)}<span class="md-token md-token-heading">${renderInlineSourceTokens(content)}</span></span>`
112	      );
113	      continue;
114	    }
115	
116	    if (trimmedLine.startsWith("```")) {
117	      const fenceBody = line.replace(/^(\s*)```/, "$1");
118	      const language = trimmedLine.slice(3);
119	      highlightedLines.push(
120	        `<span class="md-line md-line-fence">${escapeSourceHtml(fenceBody.slice(0, fenceBody.length - language.length))}<span class="md-token md-token-fence-marker">\`\`\`</span>${language ? `<span class="md-token md-token-fence-language">${escapeSourceHtml(language)}</span>` : ""}</span>`
121	      );
122	      insideFence = !insideFence;
123	      continue;
124	    }
125	
126	    if (insideFence) {
127	      highlightedLines.push(`<span class="md-line md-line-code">${escapeSourceHtml(line) || " "}</span>`);
128	      continue;
129	    }
130	
131	    if (/^(\s*)(>\s?)(.*)$/.test(line)) {
132	      const [, indent = "", marker = "", content = ""] = line.match(/^(\s*)(>\s?)(.*)$/) ?? [];
133	      highlightedLines.push(
134	        `<span class="md-line md-line-quote">${escapeSourceHtml(indent)}<span class="md-token md-token-quote-marker">${escapeSourceHtml(marker)}</span><span class="md-token md-token-quote">${renderInlineSourceTokens(content)}</span></span>`
135	      );
136	      continue;
137	    }
138	
139	    if (/^(\s*)((?:[-*])|(?:\d+\.))(\s+)(.*)$/.test(line)) {
140	      const [, indent = "", marker = "", gap = "", content = ""] = line.match(/^(\s*)((?:[-*])|(?:\d+\.))(\s+)(.*)$/) ?? [];
141	      highlightedLines.push(
142	        `<span class="md-line md-line-list">${escapeSourceHtml(indent)}<span class="md-token md-token-list-marker">${escapeSourceHtml(marker)}</span>${escapeSourceHtml(gap)}<span class="md-token md-token-list">${renderInlineSourceTokens(content)}</span></span>`
143	      );
144	      continue;
145	    }
146	
147	    if (/^[-*_]{3,}$/.test(trimmedLine)) {
148	      highlightedLines.push(`<span class="md-line md-line-rule"><span class="md-token md-token-rule">${escapeSourceHtml(line)}</span></span>`);
149	      continue;
150	    }
151	
152	    highlightedLines.push(`<span class="md-line">${renderInlineSourceTokens(line) || " "}</span>`);
153	  }
154	
155	  return highlightedLines.join("\n");
156	}
