158	function getCursorState(markdown: string, selectionStart: number, selectionEnd: number): CursorState {
159	  const normalizedStart = Math.max(0, Math.min(selectionStart, markdown.length));
160	  const normalizedEnd = Math.max(normalizedStart, Math.min(selectionEnd, markdown.length));
161	  const beforeCursor = markdown.slice(0, normalizedStart);
162	  const line = beforeCursor.split("\n").length;
163	  const lastBreak = beforeCursor.lastIndexOf("\n");
164	
165	  return {
166	    line,
167	    column: normalizedStart - lastBreak,
168	    selection: normalizedEnd - normalizedStart
169	  };
170	}
