172	function getLineRange(markdown: string, start: number, end: number) {
173	  const lineStart = markdown.lastIndexOf("\n", Math.max(0, start - 1)) + 1;
174	  const nextBreak = markdown.indexOf("\n", end);
175	  const lineEnd = nextBreak === -1 ? markdown.length : nextBreak;
176	
177	  return {
178	    lineEnd,
179	    lineStart,
180	    lineText: markdown.slice(lineStart, lineEnd)
181	  };
182	}
