184	function applyMarkdownReplacement(markdown: string, selection: SelectionRange, replacement: string): { nextMarkdown: string; nextSelection: SelectionRange } {
185	  const nextMarkdown = `${markdown.slice(0, selection.start)}${replacement}${markdown.slice(selection.end)}`;
186	  const nextCursor = selection.start + replacement.length;
187	
188	  return {
189	    nextMarkdown,
190	    nextSelection: {
191	      end: nextCursor,
192	      start: nextCursor
193	    }
194	  };
195	}
