197	function indentSelectedLines(markdown: string, selection: SelectionRange, remove = false) {
198	  const lineStart = markdown.lastIndexOf("\n", Math.max(0, selection.start - 1)) + 1;
199	  const boundaryIndex = selection.end > 0 && markdown[selection.end - 1] === "\n" ? selection.end - 1 : selection.end;
200	  const nextBreak = markdown.indexOf("\n", boundaryIndex);
201	  const lineEnd = nextBreak === -1 ? markdown.length : nextBreak;
202	  const block = markdown.slice(lineStart, lineEnd);
203	  const lines = block.split("\n");
204	
205	  const transformedLines = lines.map((line) => {
206	    if (!remove) {
207	      return `  ${line}`;
208	    }
209	
210	    if (line.startsWith("  ")) {
211	      return line.slice(2);
212	    }
213	
214	    if (line.startsWith("\t")) {
215	      return line.slice(1);
216	    }
217	
218	    if (line.startsWith(" ")) {
219	      return line.slice(1);
220	    }
221	
222	    return line;
223	  });
224	
225	  const nextBlock = transformedLines.join("\n");
226	  const nextMarkdown = `${markdown.slice(0, lineStart)}${nextBlock}${markdown.slice(lineEnd)}`;
227	  const firstLineDelta = transformedLines[0].length - lines[0].length;
228	
229	  return {
230	    nextMarkdown,
231	    nextSelection: {
232	      end: lineStart + nextBlock.length,
233	      start: Math.max(lineStart, selection.start + firstLineDelta)
234	    }
235	  };
236	}
